// Vendored fonts for pixel-accurate PDFs — the EXACT faces the app draws with,
// pulled from the device: Roboto (variable font instanced at wght 400/700) and
// Noto Serif, subset to Latin + € ° £ ¥. Auto-generated; do not edit by hand.
const F = {
  robotoRegular: '',
  robotoBold: '',
  notoSerifRegular: '',
  notoSerifBold: '',
};
// Register the four faces on a jsPDF doc instance (VFS is per-instance).
export function registerFonts(doc){
  doc.addFileToVFS('Roboto-Regular.ttf', F.robotoRegular);
  doc.addFont('Roboto-Regular.ttf', 'Roboto', 'normal');
  doc.addFileToVFS('Roboto-Bold.ttf', F.robotoBold);
  doc.addFont('Roboto-Bold.ttf', 'Roboto', 'bold');
  doc.addFileToVFS('NotoSerif-Regular.ttf', F.notoSerifRegular);
  doc.addFont('NotoSerif-Regular.ttf', 'NotoSerif', 'normal');
  doc.addFileToVFS('NotoSerif-Bold.ttf', F.notoSerifBold);
  doc.addFont('NotoSerif-Bold.ttf', 'NotoSerif', 'bold');
}
